def encrypt(plaintext: str) -> str:

    """Encrypt *plaintext* and return ``ENC:<base64-ciphertext>``."""

    if not plaintext:

        return plaintext

    f = _get_fernet()

    token = f.encrypt(plaintext.encode("utf-8"))

    return _ENC_PREFIX + token.decode("ascii")

