        pth_matches = _filter_by_color(_find_single(TORCH_EXT), screen_color)
        if safetensors_matches and pth_matches:
            logger.info("Both .safetensors and .pth %s checkpoints present in %s — preferring .safetensors.", screen_color, CHECKPOINT_DIR)
        matches = safetensors_matches or pth_matches
        chosen_ext = SAFETENSORS_EXT if safetensors_matches else TORCH_EXT
        if not matches:
            return _ensure_torch_checkpoint(screen_color)
        if len(matches) > 1:
            names = [os.path.basename(f) for f in matches]
            raise ValueError(f"Multiple {chosen_ext} {screen_color} checkpoints in {CHECKPOINT_DIR}: {names}. Keep exactly one.")
        return Path(matches[0])
    if screen_color == "blue":
        raise RuntimeError("Blue-screen support is not yet available on the MLX backend. Use --backend torch with --screen-color blue, or wait for the MLX blue release.")
    matches = _filter_by_color(_find_single(ext), screen_color)
    if len(matches) == 0:
