    repo_id = _hf_repo_for_color(screen_color)
    safetensors_filename = _hf_safetensors_for_color(screen_color)
    dest = Path(CHECKPOINT_DIR) / safetensors_filename
    hf_url = f"https://huggingface.co/{repo_id}"
