def completion(
    self, prompt: str | dict[str, Any], root_prompt: str | None = None
) -> RLMChatCompletion:

    time_start = time.perf_counter()
    self._completion_start_time = time_start
    self._consecutive_errors = 0
    self._last_error = None
    self._best_partial_answer = None

    if self.depth >= self.max_depth:
        return self._fallback_answer(prompt)

    if self.logger:
        self.logger.clear_iterations()

    with self._spawn_completion_context(prompt) as (lm_handler, environment):
        message_history = self._setup_prompt(prompt)
        compaction_count = 0
        try:
            for i in range(self.max_iterations):
                self._check_timeout(i, time_start)
                if self.compaction and hasattr(environment, "append_compaction_entry"):
                    current_tokens, threshold_tokens, max_tokens = self._get_compaction_status(message_history)
                    self.verbose.print_compaction_status(current_tokens, threshold_tokens, max_tokens)
                    if current_tokens >= threshold_tokens:
                        compaction_count += 1
                        self.verbose.print_compaction()
                        message_history = self._compact_history(lm_handler, environment, message_history, compaction_count)
                context_count = environment.get_context_count() if isinstance(environment, SupportsPersistence) else 1
                history_count = environment.get_history_count() if isinstance(environment, SupportsPersistence) else 0
                current_prompt = message_history + [build_user_prompt(root_prompt, i, context_count, history_count)]
                iteration: RLMIteration = self._completion_turn(prompt=current_prompt, lm_handler=lm_handler, environment=environment)
                self._check_iteration_limits(iteration, i, lm_handler)
                final_answer = None
                for block in iteration.code_blocks:
                    if getattr(block.result, "final_answer", None):
                        final_answer = block.result.final_answer
                        break
                if final_answer is None:
                    final_answer = find_final_answer(iteration.response, environment=environment)
                iteration.final_answer = final_answer
                if iteration.response and iteration.response.strip():
                    self._best_partial_answer = iteration.response
                if self.logger:
                    self.logger.log(iteration)
                self.verbose.print_iteration(iteration, i + 1)
                if final_answer is not None:
                    time_end = time.perf_counter()
                    usage = lm_handler.get_usage_summary()
                    self.verbose.print_final_answer(final_answer)
                    self.verbose.print_summary(i + 1, time_end - time_start, usage.to_dict())
                    if self.persistent and isinstance(environment, SupportsPersistence):
                        environment.add_history(message_history)
                    return RLMChatCompletion(root_model=self.backend_kwargs.get("model_name", "unknown") if self.backend_kwargs else "unknown", prompt=prompt, response=final_answer, usage_summary=usage, execution_time=time_end - time_start, metadata=self.logger.get_trajectory() if self.logger else None)
                new_messages = format_iteration(iteration)
                message_history.extend(new_messages)
                if self.compaction and hasattr(environment, "append_compaction_entry"):
                    environment.append_compaction_entry(new_messages)
        except KeyboardInterrupt:
            self.verbose.print_limit_exceeded("cancelled", "User interrupted execution")
            raise CancellationError(partial_answer=self._best_partial_answer, message="Execution cancelled by user (Ctrl+C)") from None
        time_end = time.perf_counter()
        final_answer = self._default_answer(message_history, lm_handler)
        usage = lm_handler.get_usage_summary()
        self.verbose.print_final_answer(final_answer)
        self.verbose.print_summary(self.max_iterations, time_end - time_start, usage.to_dict())
        if self.persistent and isinstance(environment, SupportsPersistence):
            environment.add_history(message_history)
        return RLMChatCompletion(root_model=self.backend_kwargs.get("model_name", "unknown") if self.backend_kwargs else "unknown", prompt=prompt, response=final_answer, usage_summary=usage, execution_time=time_end - time_start, metadata=self.logger.get_trajectory() if self.logger else None)

