def _get_video_duration(video_path: str) -> float:
    ffprobe_exe = shutil.which("ffprobe")
    if ffprobe_exe:
        result = subprocess.run(
            [ffprobe_exe, "-v", "quiet", "-print_format", "json", "-show_format", video_path],
            capture_output=True, text=True, check=True
