def _subcall(self, prompt: str, model: str | None = None) -> RLMChatCompletion:

    next_depth = self.depth + 1

    if model is not None:
        child_backend_kwargs = {**self.backend_kwargs, "model_name": model} if self.backend_kwargs else {"model_name": model}
    else:
        child_backend_kwargs = self.backend_kwargs

    resolved_model = model or (child_backend_kwargs.get("model_name", "unknown") if child_backend_kwargs else "unknown")

    if next_depth >= self.max_depth:
        client = get_client(self.other_backends[0], self.other_backend_kwargs[0]) if self.other_backends and self.other_backend_kwargs else get_client(self.backend, child_backend_kwargs or {})
        root_model = model or client.model_name
        start_time = time.perf_counter()
        try:
            response = client.completion(prompt)
            end_time = time.perf_counter()
            model_usage = client.get_last_usage()
            usage_summary = UsageSummary(model_usage_summaries={root_model: model_usage})
            return RLMChatCompletion(root_model=root_model, prompt=prompt, response=response, usage_summary=usage_summary, execution_time=end_time - start_time)
        except Exception as e:
            end_time = time.perf_counter()
            return RLMChatCompletion(root_model=root_model, prompt=prompt, response=f"Error: LM query failed at max depth - {e}", usage_summary=UsageSummary(model_usage_summaries={}), execution_time=end_time - start_time)

    remaining_budget = self.max_budget - self._cumulative_cost if self.max_budget is not None else None
    if remaining_budget is not None and remaining_budget <= 0:
        return RLMChatCompletion(root_model=resolved_model, prompt=prompt, response=f"Error: Budget exhausted (spent ${self._cumulative_cost:.6f} of ${self.max_budget:.6f})", usage_summary=UsageSummary(model_usage_summaries={}), execution_time=0.0)

    remaining_timeout = self.max_timeout - (time.perf_counter() - self._completion_start_time) if self.max_timeout is not None and self._completion_start_time is not None else None
    if remaining_timeout is not None and remaining_timeout <= 0:
        return RLMChatCompletion(root_model=resolved_model, prompt=prompt, response=f"Error: Timeout exhausted ({time.perf_counter() - self._completion_start_time:.1f}s of {self.max_timeout:.1f}s)", usage_summary=UsageSummary(model_usage_summaries={}), execution_time=0.0)

    prompt_preview = prompt[:80] if len(prompt) > 80 else prompt

    if self.on_subcall_start:
        try:
            self.on_subcall_start(next_depth, str(resolved_model), prompt_preview)
        except Exception:
            pass

    subcall_start = time.perf_counter()
    error_msg: str | None = None

    child = RLM(
        backend=self.backend,
        backend_kwargs=child_backend_kwargs,
        environment=self.environment_type,
        environment_kwargs=self.environment_kwargs,
        depth=next_depth,
        max_depth=self.max_depth,
        max_iterations=self.max_iterations,
        max_budget=remaining_budget,
        max_timeout=remaining_timeout,
        max_tokens=self.max_tokens,
        max_errors=self.max_errors,
        custom_system_prompt=self.system_prompt,
        other_backends=self.other_backends,
        other_backend_kwargs=self.other_backend_kwargs,
        logger=RLMLogger() if self.logger else None,
        verbose=False,
        custom_tools=self.custom_sub_tools,
        custom_sub_tools=self.custom_sub_tools,
        max_concurrent_subcalls=self.max_concurrent_subcalls,
        on_subcall_start=self.on_subcall_start,
        on_subcall_complete=self.on_subcall_complete,
    )

    try:
        result = child.completion(prompt, root_prompt=None)
        if result.usage_summary and result.usage_summary.total_cost:
            self._cumulative_cost += result.usage_summary.total_cost
        return result
    except BudgetExceededError as e:
        self._cumulative_cost += e.spent
        error_msg = f"Budget exceeded - {e}"
        return RLMChatCompletion(root_model=resolved_model, prompt=prompt, response=f"Error: Child RLM budget exceeded - {e}", usage_summary=UsageSummary(model_usage_summaries={}), execution_time=time.perf_counter() - subcall_start)
    except Exception as e:
        error_msg = str(e)
        return RLMChatCompletion(root_model=resolved_model, prompt=prompt, response=f"Error: Child RLM completion failed - {e}", usage_summary=UsageSummary(model_usage_summaries={}), execution_time=time.perf_counter() - subcall_start)
    finally:
        child.close()
        if self.on_subcall_complete:
            try:
                duration = time.perf_counter() - subcall_start
                self.on_subcall_complete(next_depth, str(resolved_model), duration, error_msg)
            except Exception:
                pass

