    except Exception as exc:  # pragma: no cover - environment specific

        raise RuntimeError(

            "ffmpeg not found on PATH and imageio-ffmpeg is not available. "

            "Install ffmpeg system-wide or `uv add imageio-ffmpeg`."

        ) from exc

